#include <stdio.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long N, M;
        scanf("%lld %lld", &N, &M);
        printf("%lld\n", N * M);
    }
    return 0;
}

